package br.com.samuel.stockly;
import android.content.*;import android.database.*;import android.database.sqlite.*;import java.security.*;import java.text.*;import java.util.*;
public class DB extends SQLiteOpenHelper{static final String DBN="stockly_tutorial_v4.db";DB(Context c){super(c,DBN,null,1);}public void onCreate(SQLiteDatabase db){db.execSQL("CREATE TABLE users(id INTEGER PRIMARY KEY AUTOINCREMENT,name TEXT,email TEXT UNIQUE,password_hash TEXT,salt TEXT,role TEXT,status TEXT DEFAULT 'ACTIVE',created_at INTEGER DEFAULT(strftime('%s','now')),last_login INTEGER)");db.execSQL("CREATE TABLE products(id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER,name TEXT,price REAL,quantity INTEGER,minimum_quantity INTEGER DEFAULT 1,category TEXT DEFAULT 'Geral',created_at INTEGER DEFAULT(strftime('%s','now')),updated_at INTEGER DEFAULT(strftime('%s','now')))");db.execSQL("CREATE TABLE stock_movements(id INTEGER PRIMARY KEY AUTOINCREMENT,product_id INTEGER,user_id INTEGER,type TEXT,quantity INTEGER,note TEXT,created_at INTEGER DEFAULT(strftime('%s','now')))");db.execSQL("CREATE TABLE audit_logs(id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER,action TEXT,entity TEXT,details TEXT,created_at INTEGER DEFAULT(strftime('%s','now')))");}public void onUpgrade(SQLiteDatabase db,int o,int n){db.execSQL("DROP TABLE IF EXISTS audit_logs");db.execSQL("DROP TABLE IF EXISTS stock_movements");db.execSQL("DROP TABLE IF EXISTS products");db.execSQL("DROP TABLE IF EXISTS users");onCreate(db);}int countUsers(){Cursor c=getReadableDatabase().rawQuery("SELECT COUNT(*) FROM users",null);try{return c.moveToFirst()?c.getInt(0):0;}finally{c.close();}}long register(String name,String email,String pass)throws Exception{return createUser(name,email,pass,countUsers()==0?"ADMIN":"EMPLOYEE");}long createUser(String name,String email,String pass,String role)throws Exception{String salt=salt();ContentValues v=new ContentValues();v.put("name",name.trim());v.put("email",email.trim().toLowerCase());v.put("password_hash",sha(pass+salt));v.put("salt",salt);v.put("role",role);long id=getWritableDatabase().insertOrThrow("users",null,v);log(id,"CREATE_USER","users","Usuário "+email+" como "+role);return id;}Login login(String email,String pass)throws Exception{Cursor c=getReadableDatabase().query("users",null,"email=? AND status='ACTIVE'",new String[]{email.trim().toLowerCase()},null,null,null);try{if(!c.moveToFirst())return null;String salt=c.getString(c.getColumnIndexOrThrow("salt"));if(!sha(pass+salt).equals(c.getString(c.getColumnIndexOrThrow("password_hash"))))return null;long id=c.getLong(c.getColumnIndexOrThrow("id"));log(id,"LOGIN","users","Login realizado");return new Login(id,c.getString(c.getColumnIndexOrThrow("name")),c.getString(c.getColumnIndexOrThrow("role")));}finally{c.close();}}List<UserAccount> users(){ArrayList<UserAccount> l=new ArrayList<>();Cursor c=getReadableDatabase().query("users",null,null,null,null,null,"name");try{while(c.moveToNext())l.add(new UserAccount(c.getLong(c.getColumnIndexOrThrow("id")),c.getString(c.getColumnIndexOrThrow("name")),c.getString(c.getColumnIndexOrThrow("email")),c.getString(c.getColumnIndexOrThrow("role")),c.getString(c.getColumnIndexOrThrow("status"))));}finally{c.close();}return l;}void cycleRole(long id){Cursor c=getReadableDatabase().query("users",new String[]{"role"},"id=?",new String[]{""+id},null,null,null);try{if(c.moveToFirst()){String r=c.getString(0),n=r.equals("ADMIN")?"EMPLOYEE":r.equals("EMPLOYEE")?"VIEWER":"ADMIN";ContentValues v=new ContentValues();v.put("role",n);getWritableDatabase().update("users",v,"id=?",new String[]{""+id});log(id,"CHANGE_ROLE","users","Novo perfil: "+n);}}finally{c.close();}}void toggleStatus(long id){Cursor c=getReadableDatabase().query("users",new String[]{"status"},"id=?",new String[]{""+id},null,null,null);try{if(c.moveToFirst()){String n=c.getString(0).equals("ACTIVE")?"INACTIVE":"ACTIVE";ContentValues v=new ContentValues();v.put("status",n);getWritableDatabase().update("users",v,"id=?",new String[]{""+id});log(id,"CHANGE_STATUS","users","Novo status: "+n);}}finally{c.close();}}long insertProduct(long uid,String name,double price,int qty,int min,String cat){ContentValues v=pv(uid,name,price,qty,min,cat);long id=getWritableDatabase().insert("products",null,v);move(id,uid,"ENTRADA",qty,"Cadastro inicial");log(uid,"CREATE_PRODUCT","products",name);return id;}void updateProduct(long id,long uid,String name,double price,int qty,int min,String cat){Product old=findProduct(id);getWritableDatabase().update("products",pv(uid,name,price,qty,min,cat),"id=?",new String[]{""+id});if(old!=null&&old.qty!=qty)move(id,uid,qty>old.qty?"ENTRADA":"SAIDA",Math.abs(qty-old.qty),"Ajuste por edição");log(uid,"UPDATE_PRODUCT","products",name);}void deleteProduct(long id,long uid){Product p=findProduct(id);getWritableDatabase().delete("products","id=?",new String[]{""+id});log(uid,"DELETE_PRODUCT","products",p==null?"id="+id:p.name);}Product findProduct(long id){Cursor c=getReadableDatabase().query("products",null,"id=?",new String[]{""+id},null,null,null);try{return c.moveToFirst()?prod(c):null;}finally{c.close();}}List<Product> products(){ArrayList<Product> l=new ArrayList<>();Cursor c=getReadableDatabase().query("products",null,null,null,null,null,"name");try{while(c.moveToNext())l.add(prod(c));}finally{c.close();}return l;}ContentValues pv(long uid,String n,double p,int q,int m,String cat){ContentValues v=new ContentValues();v.put("user_id",uid);v.put("name",n.trim());v.put("price",p);v.put("quantity",q);v.put("minimum_quantity",m);v.put("category",cat.trim().isEmpty()?"Geral":cat.trim());return v;}Product prod(Cursor c){return new Product(c.getLong(c.getColumnIndexOrThrow("id")),c.getLong(c.getColumnIndexOrThrow("user_id")),c.getString(c.getColumnIndexOrThrow("name")),c.getDouble(c.getColumnIndexOrThrow("price")),c.getInt(c.getColumnIndexOrThrow("quantity")),c.getInt(c.getColumnIndexOrThrow("minimum_quantity")),c.getString(c.getColumnIndexOrThrow("category")));}void move(long pid,long uid,String type,int qty,String note){ContentValues v=new ContentValues();v.put("product_id",pid);v.put("user_id",uid);v.put("type",type);v.put("quantity",qty);v.put("note",note);getWritableDatabase().insert("stock_movements",null,v);}void log(long uid,String a,String e,String d){ContentValues v=new ContentValues();v.put("user_id",uid);v.put("action",a);v.put("entity",e);v.put("details",d);getWritableDatabase().insert("audit_logs",null,v);}List<Entry> entries(String table){ArrayList<Entry> l=new ArrayList<>();String sql=table.equals("audit_logs")?"SELECT action||' • '||entity,IFNULL(details,'')||' • usuário: '||IFNULL(user_id,'-') FROM audit_logs ORDER BY id DESC":"SELECT type||' • produto '||IFNULL(product_id,'-'),'Qtd: '||quantity||' • usuário: '||user_id||' • '||IFNULL(note,'') FROM stock_movements ORDER BY id DESC";Cursor c=getReadableDatabase().rawQuery(sql,null);try{while(c.moveToNext())l.add(new Entry(c.getString(0),c.getString(1)));}finally{c.close();}return l;}String dump(String table){if(!Arrays.asList("users","products","stock_movements","audit_logs").contains(table))return"Tabela inválida";Cursor c=getReadableDatabase().rawQuery("SELECT * FROM "+table+" ORDER BY id DESC",null);StringBuilder sb=new StringBuilder();try{String[] cols=c.getColumnNames();for(String col:cols)sb.append(col).append('\t');sb.append('\n');while(c.moveToNext()){for(String col:cols)sb.append(c.getString(c.getColumnIndexOrThrow(col))).append('\t');sb.append('\n');}if(c.getCount()==0)sb.append("Nenhum registro encontrado.");}finally{c.close();}return sb.toString();}int rows(String t){Cursor c=getReadableDatabase().rawQuery("SELECT COUNT(*) FROM "+t,null);try{return c.moveToFirst()?c.getInt(0):0;}finally{c.close();}}static String salt(){byte[] b=new byte[16];new SecureRandom().nextBytes(b);return hex(b);}static String sha(String s)throws Exception{return hex(MessageDigest.getInstance("SHA-256").digest(s.getBytes("UTF-8")));}static String hex(byte[] b){StringBuilder sb=new StringBuilder();for(byte x:b)sb.append(String.format("%02x",x));return sb.toString();}static class Login{final long id;final String name,role;Login(long i,String n,String r){id=i;name=n;role=r;}}}
